        java.util.HashMap<Integer, java.util.ArrayList<Pair<Integer, Integer>>> edges = new java.util.HashMap<>();
        for (int i = 0; i < graph.length; i++) {
            for (int j = i + 1; j < graph.length; j++) {
                if (graph[i][j] == 1) {
                    edges.put(i, new java.util.ArrayList<>(Arrays.asList(new Pair<>(j, graph[i][j]))));
                    edges.put(j, new java.util.ArrayList<>(Arrays.asList(new Pair<>(i, graph[i][j]))));
                }
            }
        }

        java.util.PriorityQueue<Pair<Integer, Integer>> pq = new java.util.PriorityQueue<>(new java.util.Comparator<Pair<Integer, Integer>>() {
            @Override
            public int compare(Pair<Integer, Integer> o1, Pair<Integer, Integer> o2) {
                return o1.second - o2.second;
            }
        });
        for (Pair<Integer, Integer> edge : edges.get(0)) {
            pq.add(edge);
        }
        boolean[] visited = new boolean[graph.length];
        visited[0] = true;

        while (!pq.isEmpty()) {
            Pair<Integer, Integer> u = pq.poll();
            if (visited[u.first]) {
                continue;
