        pq.push(edge);
    }
    let visited = {0: true};

    while (pq.length) {
        let u = pq.shift();
        if (visited[u[0]]) {
            continue;
        }
        visited[u[0]] = true;
        for (let edge of edges[u[0]]) {
            if (!visited[edge[0]]) {
                pq.push(edge);
            }
        }
    }

